#include <mpi.h>
#include <omp.h>
#include <vector>
#include <algorithm>
#include <cmath>

struct Point {
    double x, y;
};

double distance(Point const& p1, Point const& p2) {
    return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

// Function to sort points by polar angle with respect to the lowest point
bool comparePoints(const Point &p1, const Point &p2) {
    return atan2(p1.y - p2.y, p1.x - p2.x) < atan2(p2.y - p2.y, p2.x - p2.x);
}

// Graham's scan algorithm to find the convex hull
std::vector<Point> grahamScan(std::vector<Point>& points) {
    std::sort(points.begin(), points.end());
    std::vector<Point> hull;
    for (int i = 0; i < points.size(); ++i) {
        while (hull.size() >= 2 && crossProduct(hull[hull.size()-2], hull.back(), points[i]) <= 0)
            hull.pop_back();
        hull.push_back(points[i]);
    }
    return hull;
}

// Cross product to determine the orientation of three points
double crossProduct(Point a, Point b, Point c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

double convexHullPerimeter(std::vector<Point> const& points) {
    double perimeter = 0.0;

    // Sort points using OpenMP
    #pragma omp parallel for schedule(static)
    for(int i = 0; i < points.size(); ++i) {
        std::sort(points.begin(), points.end(), comparePoints);
    }

    // Compute convex hull on each rank
    std::vector<Point> localHull = grahamScan(points);

    // Gather all local hulls to rank 0 using MPI
    int numRanks;
    MPI_Comm_size(MPI_COMM_WORLD, &numRanks);

    if (MPI_ROOT == MPI_COMM_RANK) {
        for(int i = 1; i < numRanks; ++i) {
            std::vector<Point> remoteHull(points.size());
            MPI_Recv(&remoteHull[0], points.size(), MPI_DOUBLE, MPI_ANY_SOURCE, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);

            // Update local hull with the received convex hull
            for (auto& p : remoteHull) {
                if (!localHull.empty() && !std::find(localHull.begin(), localHull.end(), p))
                    localHull.push_back(p);
            }
        }

        // Compute perimeter of the combined convex hull on rank 0
        for(int i = 1; i < localHull.size(); ++i) {
            perimeter += distance(localHull[i-1], localHull[i]);
        }
        perimeter += distance(localHull.back(), localHull.front());
    } else {
        // Send the computed convex hull to rank 0
        MPI_Send(&localHull[0], points.size(), MPI_DOUBLE, MPI_ROOT, 0, MPI_COMM_WORLD);
    }

    return perimeter;
}
